<?php $title='Dashboard';require __DIR__.'/partials/header.php';?><div class="d-flex justify-content-between align-items-center mb-4"><div><h1 class="h3 mb-1">Stream dashboard</h1><p class="text-secondary mb-0">One active stream is enforced by the stream service.</p></div><span class="badge text-bg-<?= $active?'success':'secondary' ?> fs-6"><?=e($active['status']??'stopped')?></span></div><?php if($active): ?><div class="card border-success mb-4"><div class="card-body"><h2 class="h5">Now streaming: <?=e($active['channel_name'])?></h2><p class="mb-2">Playlist: <?=e($active['playlist_name'])?> · Started: <?=e($active['started_at']??'Pending')?></p><form method="post" action="/streams/stop"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><input type="hidden" name="stream_id" value="<?=e((string)$active['id'])?>"><button class="btn btn-danger">Stop stream</button></form></div></div><?php else: ?><div class="card mb-4"><div class="card-body"><h2 class="h5">Start a stream</h2><form method="post" action="/streams/start" class="row g-3"><input type="hidden" name="_csrf" value="<?=e($_SESSION['csrf'])?>"><div class="col-md-4"><select class="form-select" name="channel_id" required><option value="">Channel</option><?php foreach($channels as $c):?><option value="<?=e((string)$c['id'])?>"><?=e($c['name'])?></option><?php endforeach?></select></div><div class="col-md-4"><select class="form-select" name="playlist_id" required><option value="">Playlist</option><?php foreach($playlists as $p):?><option value="<?=e((string)$p['id'])?>"><?=e($p['name'])?></option><?php endforeach?></select></div><div class="col-md-2"><input class="form-control" type="datetime-local" name="scheduled_start" title="Optional start time"></div><div class="col-md-2"><input class="form-control" type="datetime-local" name="scheduled_end" title="Optional end time"></div><div class="col-12"><button class="btn btn-primary">Start stream</button></div></form></div></div><?php endif?><div class="row g-3"><div class="col-md-4"><div class="card"><div class="card-body"><div class="text-secondary">Videos</div><strong class="fs-3"><?=count($videos)?></strong></div></div></div><div class="col-md-4"><div class="card"><div class="card-body"><div class="text-secondary">Disk used</div><strong class="fs-3"><?=e((string)$health['disk_used_percent'])?>%</strong></div></div></div><div class="col-md-4"><div class="card"><div class="card-body"><div class="text-secondary">Memory limit</div><strong class="fs-3"><?=e($health['memory_limit'])?></strong></div></div></div></div><?php require __DIR__.'/partials/footer.php'; ?>
